const Q_CHEMISTRY_1994=[{"id": "objective>Chemistry>1994>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A mixture of sand, ammonium chloride and sodium chloride is best separated by?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> sublimation followed by addition of water and filtration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sublimation followed by addition of water and evaporation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">addition of water followed by filtration and sublimation</div>", "<div style=\"font-family:Cambria;font-size:17px;\">addition of water followed by crystallization and sublimation</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The mixture can be separated by first sublimating the ammonium chloride. The remaining mixture of sand and sodium chloride can then be separated by adding water. The sodium chloride will dissolve in the water, and the sand can be separated by filtration.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : SEPARATION PROCESS"}, {"id": "objective>Chemistry>1994>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A pure solid usually melts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">over a wide range of temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">over a narrow range of temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at a lower temperature than the impure one</div>", "<div style=\"font-family:Cambria;font-size:17px;\">at the same temperature as the impure one</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A pure solid usually melts over a narrow range of temperature. This is because a pure substance has a specific melting point, unlike impure substances which melt over a range of temperatures due to the presence of impurities.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : BIOLING AND MELTING POINTS"}, {"id": "objective>Chemistry>1994>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">At the same temperature and pressure, 50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of nitrogen gas contains the same number of molecules as?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">25 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">40 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of chlorine</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Avogadro's law, equal volumes of all gases, at the same temperature and pressure, have the same number of molecules. Therefore, 50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of nitrogen gas contains the same number of molecules as 50 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of any other gas, including ammonia.</div>", "topic": "CHEMICAL COMBINATION : AVOGADRO'S LAW"}, {"id": "objective>Chemistry>1994>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">8g CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> occupies 11.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> at s.t.p. What volume would 22 g of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> occupy under the same condition?(C = 12, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">3.7 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">33.6 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Molar mass of methane = 16g/mol <br/> At S.T.P.  8g will occupy 11.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/> Molar mass of CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> = 44g/mol <br/> At S.T.P. 44g occupies 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> So 22g will occupy 11.2dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>1994>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">To what temperature must a gas 273 K be heated in order to double both its volume and pressure?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">298 K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">546 K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">819 K</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1092 K</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">p1=p v1=v T1=273k <br/>  <br/> P2=2p v2=2v T2=? <br/>  <br/> By general gas law p1v1/T1=p2v2/T2 <br/>  <br/> T2=2p*2v*273/p * v = 4 * 273=  1092 K</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : COMBINED GAS LAW,MOLAR VOLUME AND ATOMICITY OF GASES"}, {"id": "objective>Chemistry>1994>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">For a gas, the relative molecular mass is equal to 2Y. What is Y?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The mass of the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The vapour density of the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The volume of the gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">The temperature of the gas</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The relative molecular mass of a gas is twice its vapour density. Therefore, Y represents the vapour density of the gas.</div>", "topic": "CHEMICAL COMBINATION : AVOGADRO'S LAW"}, {"id": "objective>Chemistry>1994>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The densities of two gases, X and Y, are 0.5 g dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> and 2.0 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> respectively. <br/> What is the rate of diffusion of X relative to Y?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.1</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.0</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R =1/√D <br/>  <br/> Dx = 0.5 <br/>  <br/> Dy= 2.0 <br/>  <br/> Rx/Ry = √Dy/√Dx <br/>  <br/> √2.0/√0.5 <br/>  <br/> = 2</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>1994>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature causes an increase in the pressure of a gas because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">it decreases the number of collision between the molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the molecules of the gas bombard the walls of the container more frequently</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> it increases the number of collision between the molecules</div>", "<div style=\"font-family:Cambria;font-size:17px;\">it causes the molecules to combine</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An increase in temperature increases the kinetic energy of the gas molecules, causing them to move faster and collide with the walls of the container more frequently. This increased frequency of collisions results in an increase in pressure.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>1994>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of ammonia molecule is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> trigonal pyramidal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">octahedral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">square planar</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrahedral</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the ammonia molecule (NH3) is trigonal pyramidal.  <br/>  <br/> Ammonia has a central nitrogen atom bonded to three hydrogen atoms. The nitrogen atom has a lone pair of electrons, which repels the bonding electron pairs, causing the molecule to have a pyramidal shape.  <br/>  <br/> The bond angles in ammonia are approximately 107 degrees, which is less than the ideal tetrahedral angle of 109.5 degrees. This is due to the repulsion between the lone pair of electrons and the bonding electron pairs, which compresses the bond angles.  <br/>  <br/> Hence, the correct answer is trigonal pyramidal.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>1994>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The number of electrons in the valence shell of an element of atomic number 14 is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An element with an atomic number of 14 is silicon. Silicon is in group 14 of the periodic table, which means it has four electrons in its valence shell.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1994>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following physical properties decreases down a group in the periodic table?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Atomic radius</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ionic radius</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electropositivity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Electronegativity</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Electronegativity decreases down a group in the periodic table. Electronegativity is a measure of the tendency of an atom to attract a bonding pair of electrons. As you move down a group, the number of energy levels (shells) increases, so the outer electrons are further from the nucleus and are therefore held less tightly.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : THE PERIODIC TABLE AND PERIODICITY OF ELEMENTS"}, {"id": "objective>Chemistry>1994>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The diagram above represents an atom of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">magnesium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">helium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">neon</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Total no of electrons = 2 + 8+2 =12, so no of proton =12 and also atomic no is 12. The atom is magnesium</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1994>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Element X, Y and Z belong to a groups I, V and VII respectively. Which of the following is TRUE about the bond types of XZ and YZ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Both are electrovalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Both are covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> XZ is electrovalent and YZ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is covalent</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> XZ is covalent and YZ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is electrovalent</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Element X belongs to group I (alkali metals) which are electropositive and form electrovalent bonds. Element Y belongs to group V (pnictogens) which form covalent bonds. Therefore, XZ is electrovalent and YZ<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is covalent.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>1994>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following atoms represents deuterium?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">No protons = 1, No of neutrons = 0, No of electrons = 0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No protons = 1, No of neutrons = 0, No of electrons = 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No protons = 1, No of neutrons = 1, No of electrons = 1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">No protons = 1, No of neutrons = 2, No of electrons = 1</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Deuterium is an isotope of hydrogen with one proton, one neutron, and one electron. Therefore, the atom that represents deuterium is the one with 1 proton, 1 neutron, and 1 electron.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1994>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The set-up above would be useful for determining the amount of </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">oxygen in air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">water vapour in air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> in air</div>", "<div style=\"font-family:Cambria;font-size:17px;\">argon in air</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Anhydrous Calcium chloride is a drying agent and so it is used to remove water vapour from air. The set-up above would be useful for determining the amount of water vapour in air</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>1994>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A solid that absorbs water from the atmosphere  and forms an aqueous solution is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrophilic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">efflorescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">deliquescent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hygroscopic</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A solid that absorbs water from the atmosphere and forms an aqueous solution is deliquescent. Deliquescence is the process by which a substance absorbs moisture from the atmosphere until it dissolves in the absorbed water and forms a solution.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>1994>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A major effect of oil pollution in coastal waters is the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">destruction of marine life</div>", "<div style=\"font-family:Cambria;font-size:17px;\">desalination of the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">increase in the acidity of the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">detoxification of the water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A major effect of oil pollution in coastal waters is the destruction of marine life. Oil spills can cause a widespread death of marine life and have long-term environmental impacts.</div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>1994>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium chloride has no solubility product value because of its?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">saline nature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">high solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">low solubility</div>", "<div style=\"font-family:Cambria;font-size:17px;\">insolubility</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Sodium chloride has no solubility product value because of its high solubility. The solubility product constant (Ksp) is used to describe saturated solutions of ionic compounds of relatively low solubility. Sodium chloride is highly soluble, so it does not have a Ksp value.</div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>1994>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solubility, in moles per dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of 20.2 g of potassium trioxonitrate (V) dissolve in 100 g of water at room temperature is? <br/>  <br/> (K = 39, O = 16, N =14).</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 0.10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.20</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.00</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubility=solute/solvent * 1000/molar mass <br/> Solute= 20.2g <br/> Solvent=100g <br/> Molar mass of potassium trioxonitrate(v) (knO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) <br/> == (39+14+[16×3]) <br/> = (39+14+48) <br/> =101 <br/> Solubility = 20.2/100 × 1000/101 <br/> =20200/10100 <br/> =2. 00</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1994>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A few drops of concentrated HCl are added to about 10cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution of pH 3.4. The pH of the resulting mixtures is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">less than 3.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">greater than 3.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unaltered</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the same as that of pure water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Adding a few drops of concentrated HCl to a solution will increase the concentration of H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> ions in the solution, which will decrease the pH. Therefore, the pH of the resulting mixture is less than 3.4.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>1994>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is a base?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CO2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CaO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>PO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CaO (Calcium Oxide) is a base. A base is a substance that can accept hydrogen ions (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span>) or, more generally, donate pairs of electrons. Calcium oxide is a basic oxide and reacts with acids to form a salt and water.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1994>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">20 cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a 2.0 M solution of ethanoic acid was added to excess of 0.05 M sodium hydroxide. The mass of the salt produced is? <br/>  <br/> (Na = 23, C = 12, O = 16, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.50 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2.73 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 3.28 g</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4.54 g</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH + NaOH -- CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COONa + H2O ( equation of reaction). ratio of acid to base is 1 : 1 CAVA/CBVB = na/nb; (2.0 × 20)/0.05 × VB = 1/1 ; VB = (2.0 × 20 × 1)/(0.05 × 1) ; VB = 800cm^3. and Molar mass of CH3COONa ( which is d salt produced) = 12 + 3 + 12 + 16 + 16 + 23 = 82. therefore Solubility = mass/ molar mass × 1000/ volume ; 0.05 = mass/ 82 × 1000/ 800 ; mass = (0.05 × 82 × 800)/ 1000 ; mass = 3.28 g</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>1994>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of oxygen measured at s.t.p would be liberated on electrolysis by 9650 coulombs of electricity? <br/> [Molar volume of gas = 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> F = 96,500 C mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">11.2 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">1.12 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.560 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">For a diatomic divalent element like oxygen: <br/>  <br/> 4 faraday (4 *  96,500) = 1 mole of the element  = Molar volume of gas = 22.4 <br/>  <br/> 4 *  96,500 = 22.4 <br/>  <br/>   9650 = x  <br/>  <br/> x = 9650∗22.4/4∗96,500 <br/> x = 0.56dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>1994>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Crude copper could be purified by the electrolysis of concentrated copper (II) chloride if the crude copper is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">made both the anode and the cathode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made the cathode</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> made the anode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dissolved in the solution</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the electrolysis of copper (II) chloride, crude copper is made the anode. The impure copper anode dissolves into the solution to form copper (II) ions, which are then reduced at the cathode to form pure copper.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>1994>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">H(s)+ H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O → H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> + OH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span>. From the equation, it can be inferred that the?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">reaction is a double decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydride ion is a reducing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydride ion is an oxidizing agent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reaction is neutralization</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, the hydride ion (H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span>) is being oxidized to hydrogen gas (H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>), meaning it is losing electrons. Therefore, it is acting as a reducing agent, as reducing agents are substances that lose (or donate) electrons.</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>1994>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The ∆H for the reaction represented by the energy profile above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">-100 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+ 100 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">+50 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">-50 kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The change in enthalpy is the enthalpy of the products- the enthalpy of the reactants. therefore that is 100 - 50= +50KJ/mol.</div>", "topic": "ENERGY CHANGES : ENDOTHERMIC AND EXOTHERMIC REACTIONS"}, {"id": "objective>Chemistry>1994>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An anhydride is an oxide of non-metal?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">which will not dissolve in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">whose solution in water has a pH greater than 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">whose solution in water has a pH less than 7</div>", "<div style=\"font-family:Cambria;font-size:17px;\">whose solution in water has a pH of 7</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An anhydride is a compound that forms an acid or base when combined with water. Non-metal oxides are typically acidic anhydrides, meaning they form acids when combined with water. These solutions will have a pH less than 7.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1994>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + 8H<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">+</span> (aq) + 5Fe<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span> → Mn<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3+</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">(aq)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span>. The oxidation number of manganese in the above reaction changed from?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> +7 to +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+6 to +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+5 to +2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">+4 to +2</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The oxidation number of Mn in MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span><span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> is calculated thus <br/> MnO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> <br/> x-2 <br/> x + 4(-2) = -1=x - 8= -1 <br/> X = -1 + 8 =+7 <br/> The change in oxidation no of Mn is thus from +7 to +2</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>1994>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above the activation energy is represented by </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> y - x</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x</div>", "<div style=\"font-family:Cambria;font-size:17px;\">x - z</div>", "<div style=\"font-family:Cambria;font-size:17px;\">y</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Activation = Activated energy of the reactants - energy complex(Ea). The activation energy of a reaction is equal to the difference between the energy of the activated complex and the energy of the reactants. </div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>1994>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is TRUE of Le Chatelier's Principle for an exothermic reaction?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Increase in temperature will cause an increase in the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Increase in temperature will cause a decrease in the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition of a catalyst will cause an increase in the equilibrium constant</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Addition of a catalyst will cause a decrease in the equilibrium constant</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to Le Chatelier's Principle, if a system at equilibrium is subjected to a change in temperature, pressure, or concentration of components, the system will shift its equilibrium position to counteract the effect of the disturbance. For an exothermic reaction, an increase in temperature will shift the equilibrium to the left, favoring the reactants, and thus decreasing the equilibrium constant.</div>", "topic": "CHEMICAL EQUILIBRA : LE CHATELIER'S PRINCIPLE AND EQUILIBRIUM CONSTANT"}, {"id": "objective>Chemistry>1994>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following are produced when ammonium trioxonitrate (V) crystals are cautiously heated in a hard glass round bottomed flask?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O and steam</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> and ammonia</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> and NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO and NO2</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When ammonium trioxonitrate (V) crystals are heated, they decompose to form nitrous oxide (N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O) and water (steam).</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>1994>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> 2HCl(aq) + CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> → CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l)</span> + CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> from the reaction above, which of the following curves represents the consumption of calcium trioxocarbonate (IV) as dilute HCl is added to it? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">L</div>", "<div style=\"font-family:Cambria;font-size:17px;\">M</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N</div>", "<div style=\"font-family:Cambria;font-size:17px;\">P</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concentration of the CaCO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> decreases as the reaction time increases. As dilute HCl is added  less CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is formed</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1994>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> In the diagram above, R is a mixture of?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> potassium trioxochlorate (VII) and concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> potassium tetraxochlorate (V) and concentrated H2SO4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium tetratoxomanganate (VII) and concentrated HCI</div>", "<div style=\"font-family:Cambria;font-size:17px;\">manganese (IV) oxide and concentrated HCI</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">R is a potassium tetratoxomanganate (VII) and concentrated HCI</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}, {"id": "objective>Chemistry>1994>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these metals CANNOT replace hydrogen from alkaline solutions?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zinc</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tin</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Iron</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium, zinc an tin react with both acids and alkalis to liberate hydrogen and so are all amphoteric metals. Iron react only with acids and not with alkalis and so is not amphoteric.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM~~METALS AND THEIR COMPOUNDS : ZINC~~METALS AND THEIR COMPOUNDS : TIN~~METALS AND THEIR COMPOUNDS : IRON"}, {"id": "objective>Chemistry>1994>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Clothes should be properly rinsed with water after bleaching because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the bleach decolourizes the cothes</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine reacts with fabrics during bleaching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the clothes are sterilized during bleaching</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen chloride solution is produced during bleaching</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Clothes should be properly rinsed with water after bleaching because hydrogen chloride solution is produced during bleaching. If not properly rinsed, this acidic solution can damage the fabric.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1994>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of these solutions will give a white precipitate with a solution of barium chloride acidified with hydrochloric acid?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxocarbonate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium tetraoxosulphate (VI)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxosulphate (IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium sulphide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Barium chloride reacts with sodium tetraoxosulphate (VI) to form barium sulphate, which is a white precipitate. The reaction is: BaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> + Na<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> -> BaSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> (white precipitate) + 2NaCl.</div>", "topic": "ACID BASE AND SALTS : QUALITATIVE COMPARISON"}, {"id": "objective>Chemistry>1994>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is NOT directly dissolved in water in the preparation of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> by the contact process because?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> the reaction between SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and water is violently exothermic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">acid is usually added to water and never water to acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> does not dissolve in water readily</div>", "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is an acid gas</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> is not directly dissolved in water in the preparation of H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> by the contact process because the reaction between SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span> and water is violently exothermic. This means that the reaction releases a large amount of heat, which can be dangerous.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1994>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an electrolytic set-up to protect iron from corrosion, the iron is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">made with the cathode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">made with the anode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">used with a metal of lower electropositive potential</div>", "<div style=\"font-family:Cambria;font-size:17px;\">initially coated with tin</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an electrolytic set-up to protect iron from corrosion, the iron is made the cathode. This is because in the process of cathodic protection, the metal to be protected is made the cathode, and a more reactive metal is made the anode. The more reactive metal corrodes in preference to the protected metal.</div>", "topic": "ELECTROLYSIS : CORROSION"}, {"id": "objective>Chemistry>1994>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is NOT true of metals?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">They are good conductors of electricity</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They ionize by electron loss</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Their oxides are acidic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">They have high melting points</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The statement that the oxides of metals are acidic is not true. Metal oxides are generally basic in nature. They react with acids to form salt and water.</div>", "topic": "METALS AND THEIR COMPOUNDS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>1994>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the correct order of decreasing activity of the metals Fe, Ca, Al and Na?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Fe> Ca> Al> Na</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Na> Ca> Al> Fe</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Al> Fe> Na> Ca</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> Ca> Na> Fe>, Al</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The correct order of decreasing activity of the metals Fe, Ca, Al and Na is Na > Ca > Al > Fe. This is based on the reactivity series of metals, where sodium (Na) is more reactive than calcium (Ca), which is more reactive than aluminium (Al), which is more reactive than iron (Fe).</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>1994>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is NOT an isomers of 2,2-dimethylbutane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> 2-methylbutane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-methylpentane</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 2,3-dimethylbutane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpentane</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Isomers are those organic compounds that have the same molecular formula but different structural formula. 2-methylbutane has the molecular formular C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1994>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> The IUPAC name of the compound above is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2,2-dimethyl but -1-yne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2,2-dmethyl but -1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> 3,3-dimethyl but -1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3,3-dimethyl but-1-yne</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Numbering of the carbon atom from right to left due to the presence of the double bond. 3,3-dimethyl but-1-ene is an alkene, also known as an olefin, with the chemical formula C6H12. It is a colorless liquid with a characteristic gasoline-like odor. It is slightly soluble in water and miscible with most organic solvents.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1994>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium is added to ethanol, the products are?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium hydroxide and hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium ethoxide and water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sodium ethoxide and hydrogen</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium is added to ethanol, the products are sodium ethoxide and hydrogen. This is a type of reaction known as an acid-base reaction, where ethanol (the acid) reacts with sodium (the base) to produce sodium ethoxide and hydrogen gas.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : HYDROGEN"}, {"id": "objective>Chemistry>1994>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula of alkanones is?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">RCHO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>CO</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> RCOOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RCOOR</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula of alkanones is R2CO. Alkanones are a type of organic compound known as ketones, which have a carbonyl group (C=O) bonded to two other carbon atoms.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>1994>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium ethanoate is treated with a few drops of concentrated tetraoxosulphate(vi)acid. one of the products is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\"> CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>COOCH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When sodium ethanoate is treated with a few drops of concentrated tetraoxosulphate(vi)acid, one of the products is CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COOH (acetic acid). This is because the sodium ethanoate reacts with the acid to produce acetic acid and sodium ions.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>1994>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One mole of a hydrocarbon contains 48 g of carbon. If it vapour density is 28, the hydrocarbon is? <br/>  (C = 12, H = 1)</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an alkane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an alkene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an alkyne</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aromatic</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Relative Molar mass =2  * 28=56 <br/> Let the hydrocarbon  be CxHy <br/> Mass of carbon present= 48g=Cx  <br/> Mass of hydrogen present = 56 -48=Hy <br/> Cx =48/12=4, Hy=8 <br/> CxHY=C4H8(i.e butene)</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>1994>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the diagram above to answer this question. <br/>  <br/> The reaction taking place in flask G is known as? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrolysis</div>", "<div style=\"font-family:Cambria;font-size:17px;\">double decomposition</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dehydration</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyrolysis</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dehydration of ethanol using excess concentrated H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span> at a temperature of about 170<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">o</span>C yields ethene</div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>1994>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/> <img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/> <br/> Use the diagram above to answer this question. The caustic soda solution in the conical flask serves to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dry ethene gas</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove carbon (iv) oxides from ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\"> remove carbon (ii) oxide from ethene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">remove sulphur (iv) oxide from ethene</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Caustic soda, NaOH solution is used to absorb any carbon (IV) oxide, or Sulphur (IV) oxide produced during the reaction gas being absorbed</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>1994>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following orbitals of carbon are mixed with hydrogen in methane?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1s and 2p</div>", "<div style=\"font-family:Cambria;font-size:17px;\">1p and 2s</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2s and 2p</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2s and 3p</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The orbitals of carbon that are mixed with hydrogen in methane are the 2s and 2p orbitals. This is because carbon is in the second period of the periodic table, so it uses its second shell (2s and 2p orbitals) for bonding.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>1994>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following reagents will confirm the presence of unsaturation in a compound?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"> Fehling's solution</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bromine water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Tollen's reagent</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Benedict's solution</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Bromine water is used as a test for unsaturation. It is decolorized by alkenes (unsaturated hydrocarbons) due to the addition reaction that takes place, which confirms the presence of unsaturation in a compound.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}];
